#include<iostream>
#include<cstdio>
#include<algorithm>
using namespace std;
int n, l, t, ans[10005], maxans, a;
int main() {
	cin >> n;
	for (int i = 1; i <= n; i++) {
		cin >> a;
		cin >> l;
		int b = 0;
		while (1) {
			cin >> t;
			if (t == 0) {
				break;
			}
			b = max(ans[t], b);
		}
		ans[a] = b + l;
		maxans = max(ans[i], maxans);
	}
	cout<< maxans;
	return 0;
}
